import pytest
from <helper_fn> import fhir_client, clinician_token, create_patient, delete_resource

@pytest.fixture()
def ctx():
    token = clinician_token()
    patient_id = create_patient(token)
    yield {"token": token, "patient_id": patient_id}
    delete_resource(token, f"Patient/{patient_id}")

def test_medication_request_warns_on_allergy_conflict_after_allergy_recorded(ctx):
    client = fhir_client(ctx["token"])
    allergy_payload = {
        "resourceType": "AllergyIntolerance",
        "clinicalStatus": {"coding": [{"code": "active"}]},
        "patient": {"reference": f"Patient/{ctx['patient_id']}"},
        "code": {"coding": [{"system": "http://snomed.info/sct", "code": "372687004", "display": "Penicillin"}]}
    }
    ai_resp = client.post("/AllergyIntolerance", json=allergy_payload)
    assert ai_resp.status_code == 201, ai_resp.text
    ai_id = ai_resp.json()["id"]
    med_payload = {
        "resourceType": "MedicationRequest",
        "status": "active",
        "intent": "order",
        "subject": {"reference": f"Patient/{ctx['patient_id']}"},
        "medicationCodeableConcept": {"coding": [{"system": "http://snomed.info/sct", "code": "372687004"}]}
    }
    med_resp = client.post("/MedicationRequest", json=med_payload)
    assert med_resp.status_code in (201, 422), med_resp.text
    body = med_resp.json()
    if med_resp.status_code == 422:
        issues = body.get("issue", [])
        codes = [i.get("code", "") for i in issues]
        assert any("drug-allergy" in c for c in codes)
    else:
        warning = body.get("extension", [])
        assert any("drug-allergy" in str(w) for w in warning)
    for ref in [f"AllergyIntolerance/{ai_id}", f"Patient/{ctx['patient_id']}"]:
        audit = client.get(f"/AuditEvent?entity={ref}")
        assert audit.status_code == 200
        assert len(audit.json().get("entry", [])) >= 1
    if med_resp.status_code == 201:
        delete_resource(ctx["token"], f"MedicationRequest/{body['id']}")
    delete_resource(ctx["token"], f"AllergyIntolerance/{ai_id}")
